#include <stdio.h>

int main() {
    int number = 29, i = 2, is_prime = 1;
    while (i <= number / 2) {
        if (number % i == 0) {
            is_prime = 0;
            break;
        }
        i++;
    }
    if (is_prime) printf("%d is a prime number.\n", number);
    else printf("%d is not a prime number.\n", number);
    return 0;
}
